    @Test
    fun ankiSetNoteTagsTest() =
        runTest {
            val models = col.notetypes
            val didA = addDeck("Test", setAsSelected = true)
            val basic = models.byName(BASIC_MODEL_NAME)
            basic!!.put("did", didA)
            val note = addBasicNote("foo", "bar")
            note.addTag("oldTag")
            col.updateNote(note)

            val reviewer: Reviewer = startReviewer()
            val jsapi = reviewer.jsApi

            waitForAsyncTasksToComplete()

            val noteId = reviewer.currentCard!!.nid

            // Verify old tag exists
            var noteCheck = col.getNote(noteId)
            assertThat(noteCheck.tags.contains("oldTag"), equalTo(true))

            // Set new tags (replacing old ones)
            val newTags = JSONArray().apply {
                put("newTag1")
                put("newTag2")
            }
            val data = JSONObject().apply {
                put("noteId", noteId)
                put("tags", newTags)
            }.toString()

            val result = getDataFromRequest("setNoteTags", jsapi, data)
            assertThat(result, equalTo(formatApiResult(true)))

            waitForAsyncTasksToComplete()

            // Verify tags were replaced
            noteCheck = col.getNote(noteId)
            assertThat(noteCheck.tags.contains("oldTag"), equalTo(false))
            assertThat(noteCheck.tags.contains("newTag1"), equalTo(true))
            assertThat(noteCheck.tags.contains("newTag2"), equalTo(true))
        }

    @Test
    fun ankiRemoveTagBySettingTagsTest() =
        runTest {
            // Test the use case: remove a tag by getting tags, filtering, and setting
            val models = col.notetypes
            val didA = addDeck("Test", setAsSelected = true)
            val basic = models.byName(BASIC_MODEL_NAME)
            basic!!.put("did", didA)
            val note = addBasicNote("foo", "bar")
            note.addTag("keepTag")
            note.addTag("removeTag")
            col.updateNote(note)

            val reviewer: Reviewer = startReviewer()
            val jsapi = reviewer.jsApi

            waitForAsyncTasksToComplete()

            val noteId = reviewer.currentCard!!.nid

            // Get current tags
            val getTagsData = JSONObject().apply {
                put("noteId", noteId)
            }.toString()
            val getResult = getDataFromRequest("getNoteTags", jsapi, getTagsData)
            val jsonGetResult = JSONObject(getResult)
            val currentTagsJson = JSONArray(jsonGetResult.getString(VALUE_KEY))
            val currentTags = (0 until currentTagsJson.length()).map { currentTagsJson.getString(it) }

            // Filter out the tag to remove
            val filteredTags = currentTags.filter { it != "removeTag" }

            // Set the filtered tags
            val newTagsArray = JSONArray().apply {
                filteredTags.forEach { put(it) }
            }
            val setTagsData = JSONObject().apply {
                put("noteId", noteId)
                put("tags", newTagsArray)
            }.toString()
            val setResult = getDataFromRequest("setNoteTags", jsapi, setTagsData)
            assertThat(setResult, equalTo(formatApiResult(true)))

            waitForAsyncTasksToComplete()

            // Verify removeTag is gone and keepTag remains
            val noteCheck = col.getNote(noteId)
            assertThat(noteCheck.tags.contains("keepTag"), equalTo(true))
            assertThat(noteCheck.tags.contains("removeTag"), equalTo(false))
        }

